from typing import List
from collections import deque

def solve(edges: List[List[int]], online: List[bool], k: int) -> int:
    n = len(online)
    original_adj = [[] for _ in range(n)]
    in_degree = [0] * n
    for u, v, cost in edges:
        original_adj[u].append(v)
        in_degree[v] += 1

    # Kahn's algorithm for topological sort
    q = deque()
    for i in range(n):
        if in_degree[i] == 0:
            q.append(i)
    topological_order = []
    while q:
        u = q.popleft()
        topological_order.append(u)
        for v in original_adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                q.append(v)

    # Find max edge cost
    max_cost = 0
    for u, v, cost in edges:
        if cost > max_cost:
            max_cost = cost

    low, high = 0, max_cost
    ans = -1

    def is_possible(m):
        filtered_edges = []
        for u, v, cost in edges:
            if online[u] and online[v] and cost >= m:
                filtered_edges.append((u, v, cost))
        adj = [[] for _ in range(n)]
        for u, v, cost in filtered_edges:
            adj[u].append((v, cost))
        INF = float('inf')
        dist = [INF] * n
        dist[0] = 0
        for u in topological_order:
            if not online[u]:
                continue
            for v, cost in adj[u]:
                if dist[v] > dist[u] + cost:
                    dist[v] = dist[u] + cost
        return dist[n-1] <= k

    while low <= high:
        mid = (low + high) // 2
        if is_possible(mid):
            ans = mid
            low = mid + 1
        else:
            high = mid - 1

    return ans if ans != -1 else -1
